import jwt

def decode_jwt(token, secret_key, algorithms=['HS256']):
    try:
        decoded = jwt.decode(token, secret_key, algorithms=algorithms)
        return {
            'success': True,
            'decoded': decoded
        }
    except jwt.ExpiredSignatureError:
        return {
            'success': False,
            'error': 'Token has expired'
        }
    except jwt.InvalidTokenError:
        return {
            'success': False,
            'error': 'Invalid token'
        }

